// FindRelated queries for items related to the given id.
func (r *Repo) FindRelated(ctx context.Context, id int) ([]*Item, error) {
	const query = `SELECT * FROM items WHERE self_id = $1 OR related_id = $1`
	rows, err := r.db.QueryContext(ctx, query, id)
	if err != nil {
		return nil, fmt.Errorf("Repo.FindRelated: %w", err)
	}
	defer rows.Close()
	return scanItems(rows)
}
